import { afterEach, describe, expect, it } from 'vitest';
import { createSocket, type Socket as DgramSocket } from 'node:dgram';
import {
  createUdpPublisher,
  parseUdpTarget,
  demoFrameForBeat,
  UDP_DEFAULT_PORT,
  UDP_DEFAULT_GROUP,
  UDP_DEFAULT_TTL,
  UDP_MAX_DATAGRAM_BYTES,
  UDP_FLOW_STREAM_ID,
  UDP_FLOW_FLAGS,
  type UdpConfig,
  type UdpPublisher,
} from './skymesh-serve.mts';
import { SKYMESH_SCHEMA_VERSION } from './skymesh';
// Decode with the canonical aeon Flow codec (resolves under the gnosis test
// runner via the @a0n/aeon workspace package, subpath ./flow). The decoder
// reads the same 10-byte big-endian header the publisher writes.
// @see open-source/aeon/src/flow/FlowCodec.ts
import { FlowCodec, FORK, FOLD } from '@a0n/aeon/flow';

// We test the unicast --udp-target path against a node:dgram subscriber on
// loopback (127.0.0.1). Multicast loopback is unreliable in CI/sandbox, so the
// publisher's multicast group is set to a localhost address that goes nowhere
// here; the assertions ride the unicast leg, which carries the identical bytes.

const codec = FlowCodec.createSync();
const textDecoder = new TextDecoder();

/** Decode one FlowCodec datagram: returns the header fields + parsed JSON payload. */
function decodeFlowDatagram(msg: Buffer): {
  streamId: number;
  sequence: number;
  flags: number;
  payloadJson: string;
} {
  const bytes = new Uint8Array(msg.buffer, msg.byteOffset, msg.byteLength);
  const { frame } = codec.decode(bytes);
  return {
    streamId: frame.streamId,
    sequence: frame.sequence,
    flags: frame.flags,
    payloadJson: textDecoder.decode(frame.payload),
  };
}

/** Bind a udp4 subscriber on 127.0.0.1, return [socket, boundPort]. */
async function bindSubscriber(): Promise<[DgramSocket, number]> {
  const sock = createSocket({ type: 'udp4', reuseAddr: true });
  await new Promise<void>((resolve, reject) => {
    sock.once('error', reject);
    sock.bind(0, '127.0.0.1', () => resolve());
  });
  const port = sock.address().port;
  return [sock, port];
}

/** Wait for the next datagram, or reject after `ms`. */
function nextDatagram(sock: DgramSocket, ms = 2000): Promise<Buffer> {
  return new Promise<Buffer>((resolve, reject) => {
    const timer = setTimeout(() => {
      sock.removeListener('message', onMsg);
      reject(new Error(`no datagram within ${ms}ms`));
    }, ms);
    const onMsg = (msg: Buffer): void => {
      clearTimeout(timer);
      resolve(msg);
    };
    sock.once('message', onMsg);
  });
}

const openSockets: DgramSocket[] = [];
const openPublishers: UdpPublisher[] = [];

afterEach(() => {
  for (const p of openPublishers.splice(0)) p.close();
  for (const s of openSockets.splice(0)) {
    try {
      s.close();
    } catch {
      /* already closed */
    }
  }
});

describe('UDP wire contract', () => {
  it('exposes the fixed defaults other agents depend on', () => {
    expect(UDP_DEFAULT_PORT).toBe(8725);
    expect(UDP_DEFAULT_GROUP).toBe('239.69.0.66');
    expect(UDP_DEFAULT_TTL).toBe(1);
    // 65535 total - 20 IP header - 8 UDP header.
    expect(UDP_MAX_DATAGRAM_BYTES).toBe(65507);
    // The aeon Flow wire contract: Skymesh stream 0x5353, flags FORK|FOLD.
    expect(UDP_FLOW_STREAM_ID).toBe(0x5353);
    expect(UDP_FLOW_FLAGS).toBe(FORK | FOLD);
    expect(UDP_FLOW_FLAGS).toBe(0x05);
  });
});

describe('parseUdpTarget', () => {
  it('parses host:port', () => {
    expect(parseUdpTarget('127.0.0.1:8725')).toEqual({ host: '127.0.0.1', port: 8725 });
    expect(parseUdpTarget('localhost:1234')).toEqual({ host: 'localhost', port: 1234 });
  });
  it('rejects malformed targets', () => {
    expect(() => parseUdpTarget('nohostport')).toThrow();
    expect(() => parseUdpTarget(':8725')).toThrow();
    expect(() => parseUdpTarget('host:')).toThrow();
    expect(() => parseUdpTarget('host:70000')).toThrow();
    expect(() => parseUdpTarget('host:0')).toThrow();
  });
});

describe('createUdpPublisher', () => {
  it('returns null when disabled', () => {
    const cfg: UdpConfig = {
      enabled: false,
      port: UDP_DEFAULT_PORT,
      group: UDP_DEFAULT_GROUP,
      ttl: UDP_DEFAULT_TTL,
      targets: [],
    };
    expect(createUdpPublisher(cfg)).toBeNull();
  });

  it('delivers a FlowCodec frame (stream 0x5353) whose payload is the skymesh frame', async () => {
    const [sub, port] = await bindSubscriber();
    openSockets.push(sub);

    const cfg: UdpConfig = {
      enabled: true,
      port: 1, // multicast group send goes nowhere meaningful in CI; unicast carries the test
      group: '127.0.0.1',
      ttl: UDP_DEFAULT_TTL,
      targets: [{ host: '127.0.0.1', port }],
    };
    const pub = createUdpPublisher(cfg);
    expect(pub).not.toBeNull();
    openPublishers.push(pub!);

    const frame = demoFrameForBeat('TELEPORTED', 0);
    const expectedJson = JSON.stringify(frame);

    const received = nextDatagram(sub);
    // Give the socket a tick to finish binding before the first send.
    await new Promise((r) => setTimeout(r, 50));
    pub!.publish(frame);

    const msg = await received;
    // The datagram is a valid FlowCodec frame on the Skymesh stream.
    const decoded = decodeFlowDatagram(msg);
    expect(decoded.streamId).toBe(0x5353);
    expect(decoded.flags).toBe(0x05); // FORK | FOLD
    expect(decoded.sequence).toBe(0); // monotonic counter starts at 0
    // The Flow payload is byte-for-byte the JSON the SSE clients receive.
    expect(decoded.payloadJson).toBe(expectedJson);
    // ...and it round-trips back to a valid frame.
    const parsed = JSON.parse(decoded.payloadJson);
    expect(parsed.schemaVersion).toBe(SKYMESH_SCHEMA_VERSION);
    expect(parsed.stations).toHaveLength(2);
    expect(parsed.match).toBe(true);
  });

  it('delivers one Flow datagram per published frame, with a monotonic sequence', async () => {
    const [sub, port] = await bindSubscriber();
    openSockets.push(sub);

    const cfg: UdpConfig = {
      enabled: true,
      port: 1,
      group: '127.0.0.1',
      ttl: UDP_DEFAULT_TTL,
      targets: [{ host: '127.0.0.1', port }],
    };
    const pub = createUdpPublisher(cfg);
    openPublishers.push(pub!);

    const beats = ['LISTENING', 'WITNESS_LOCKED', 'TELEPORTED'] as const;
    const expectedPayloads = beats.map((b, i) => JSON.stringify(demoFrameForBeat(b, i)));

    const got: Buffer[] = [];
    sub.on('message', (m) => got.push(Buffer.from(m)));

    await new Promise((r) => setTimeout(r, 50));
    for (let i = 0; i < beats.length; i++) {
      pub!.publish(demoFrameForBeat(beats[i]!, i));
    }
    // Wait for all three datagrams (loopback is fast + ordered for unicast).
    await new Promise<void>((resolve, reject) => {
      const timer = setTimeout(() => reject(new Error(`only ${got.length}/3 datagrams`)), 2000);
      const iv = setInterval(() => {
        if (got.length >= 3) {
          clearInterval(iv);
          clearTimeout(timer);
          resolve();
        }
      }, 10);
    });

    const decoded = got.map(decodeFlowDatagram);
    // Each is a Skymesh Flow frame.
    for (const d of decoded) {
      expect(d.streamId).toBe(0x5353);
      expect(d.flags).toBe(0x05);
    }
    // Sequence is a monotonic 0,1,2 counter.
    expect(decoded.map((d) => d.sequence)).toEqual([0, 1, 2]);
    // Payloads round-trip in order.
    expect(decoded.map((d) => d.payloadJson)).toEqual(expectedPayloads);
  });

  it('skips (never truncates) a frame whose Flow datagram exceeds the UDP/IPv4 limit', async () => {
    const [sub, port] = await bindSubscriber();
    openSockets.push(sub);

    const cfg: UdpConfig = {
      enabled: true,
      port: 1,
      group: '127.0.0.1',
      ttl: UDP_DEFAULT_TTL,
      targets: [{ host: '127.0.0.1', port }],
    };
    const pub = createUdpPublisher(cfg);
    openPublishers.push(pub!);

    // Build an oversized frame by stuffing a huge spectrum into a station. The
    // size guard measures the full Flow datagram (10-byte header + payload), so
    // the JSON alone must already blow past the limit.
    const base = demoFrameForBeat('TELEPORTED', 0);
    const huge = JSON.parse(JSON.stringify(base));
    huge.stations[0].spectrum = new Array(40000).fill(0.123456789);
    expect(Buffer.byteLength(JSON.stringify(huge), 'utf8')).toBeGreaterThan(
      UDP_MAX_DATAGRAM_BYTES,
    );

    // Also publish a normal frame right after; only the normal one must arrive.
    const ok = demoFrameForBeat('LISTENING', 1);

    await new Promise((r) => setTimeout(r, 50));
    pub!.publish(huge); // must be skipped, not truncated
    pub!.publish(ok);

    const msg = await nextDatagram(sub);
    const decoded = decodeFlowDatagram(msg);
    expect(decoded.streamId).toBe(0x5353);
    // The huge frame consumed sequence 0 (it was encoded but skipped on the
    // size guard); the normal frame that actually went out carries sequence 1.
    expect(decoded.sequence).toBe(1);
    expect(decoded.payloadJson).toBe(JSON.stringify(ok));
  });
});
